import { memo } from "react";
import { Link } from "react-router-dom";
import { useTranslation } from "react-i18next";

const SecondaryButton = memo(({ path }) => {
  const { t } = useTranslation();
  return (
    <Link
      to={path}
      className="text-small-medium text-center w-full lg:w-fit px-3 py-2 border border-idi-950 cursor-pointer hover:bg-idi-900 hover:text-white transition-all duration-300"
    >
      {t("buttontext")}
    </Link>
  );
});

export default SecondaryButton;
